const item = $input.first();
const body = item.json.body;
const crypto = require('crypto');
const gigachatAuth = 'Basic ' + Buffer.from($env.GIGACHAT_CLIENT_ID + ':' + $env.GIGACHAT_CLIENT_SECRET).toString('base64');
const rquid = crypto.randomUUID();
return [{ json: { org_id: body.org_id, question: body.question, user_max_id: body.user_max_id, folder_structure: body.folder_structure || '', _gigachat_auth: gigachatAuth, _rquid: rquid } }];

const authResult = $input.first().json;
const inputData = $('Parse Input').first().json;
return [{ json: { ...inputData, access_token: authResult.access_token } }];

const https = require('https');
const prevData = $('Merge Auth + Input').first().json;
const apiKey = $env.YC_API_KEY;
const modelUri = 'emb://b1glrh7ge8kcm9870erg/text-search-query/latest';

const result = await new Promise((resolve, reject) => {
  const body = JSON.stringify({ modelUri, text: prevData.question });
  const req = https.request('https://llm.api.cloud.yandex.net/foundationModels/v1/textEmbedding', {
    method: 'POST',
    headers: { 'Authorization': 'Api-Key ' + apiKey, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) }
  }, (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => {
      if (res.statusCode !== 200) reject(new Error('Yandex Embed ' + res.statusCode + ': ' + data));
      else resolve(JSON.parse(data));
    });
  });
  req.on('error', reject);
  req.write(body);
  req.end();
});

return [{ json: { ...prevData, question_vector: result.embedding } }];

const searchResult = $input.first().json;
const prevData = $('Yandex: Embed Question').first().json;

const results = searchResult.result || [];
let context = '';
if (prevData.folder_structure) {
  context += '[Структура папок и документов организации]\n' + prevData.folder_structure + '\n\n---\n\n';
}
context += results.map((r, i) => { const fn = r.payload.filename; const isImage = /\.(jpg|jpeg|png|tiff?|bmp|webp)$/i.test(fn); const label = isImage ? `Источник ${i + 1} (OCR из изображения): ${fn}` : `Источник ${i + 1}: ${fn}`; return `[${label}]\n${r.payload.content}`; }).join('\n\n---\n\n');
const sources = results.map(r => ({ filename: r.payload.filename, chunk_index: r.payload.chunk_index, score: r.score }));

return [{ json: { ...prevData, context, sources, question_vector: undefined } }];

