const chatResult = $input.first().json;
const prevData = $('Build Context').first().json;
const answer = chatResult.choices[0].message.content;
return [{ json: { org_id: prevData.org_id, user_max_id: prevData.user_max_id, question: prevData.question, answer, sources: prevData.sources, sources_json: JSON.stringify(prevData.sources) } }];

const { Client } = require('pg');
const item = $input.first().json;
const client = new Client({ host: $env.APP_PG_HOST || 'db', port: parseInt($env.APP_PG_PORT || '5432'), user: $env.APP_PG_USER, password: $env.APP_PG_PASSWORD, database: ($env.APP_PG_DATABASE || 'ragkb_app') });
await client.connect();
try {
  const result = await client.query(
    'INSERT INTO "RagQuery" (organization_id, user_max_id, question, answer, source_chunks, created_at) VALUES ($1, $2, $3, $4, $5, NOW()) RETURNING id',
    [item.org_id, item.user_max_id, item.question, item.answer, JSON.stringify(item.sources)]
  );
  return [{ json: { id: result.rows[0].id } }];
} finally {
  await client.end();
}

const pgResult = $input.first().json;
const prevData = $('Extract Answer').first().json;
return [{ json: { answer: prevData.answer, sources: prevData.sources, query_id: pgResult.id } }];
